for locale_code, translations in TRANSLATIONS.items():
    filepath = os.path.join(LOCALES_DIR, f"{locale_code}.json")
    if not os.path.exists(filepath):
        continue
    with open(filepath, "r") as f:
        data = json.load(f)
    if "legal" not in data:
        data["legal"] = {}
    data["legal"]["privacy"] = translations["privacy"]
    data["legal"]["terms"] = translations["terms"]
    with open(filepath, "w") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)
    print(f"Updated {locale_code}.json")

print("Done!")
